// Aho‑Corasick implementation in C (handles multiple test cases)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define ALPH 128   // full ASCII range needed for letters, digits and '-'

typedef struct Node {
    int next[ALPH];
    int link;               // failure link
    int out;                // head of linked list of pattern indices ending here
    struct Node *out_next; // next node in output chain (via failure links)
} Node;

typedef struct OutNode {
    int idx;                // pattern index
    struct OutNode *next;   // next pattern ending at the same trie node
} OutNode;

Node *nodes;
int node_cnt;
OutNode *out_nodes;
int out_cnt;
int *freq; // frequency array for current test case

int new_node() {
    Node *n = &nodes[node_cnt];
    for (int i = 0; i < ALPH; ++i) n->next[i] = -1;
    n->link = -1;
    n->out = -1;
    n->out_next = NULL;
    return node_cnt++;
}

int new_out(int idx) {
    OutNode *o = &out_nodes[out_cnt];
    o->idx = idx;
    o->next = NULL;
    return out_cnt++;
}

void add_pattern(const char *s, int idx) {
    int v = 0;
    for (int i = 0; s[i]; ++i) {
        unsigned char c = s[i];
        if (nodes[v].next[c] == -1) {
            nodes[v].next[c] = new_node();
        }
        v = nodes[v].next[c];
    }
    // store pattern index in output list of node v
    int out_id = new_out(idx);
    out_nodes[out_id].next = (nodes[v].out == -1) ? NULL : &out_nodes[nodes[v].out];
    nodes[v].out = out_id;
}

void build_automaton() {
    int q[500000]; // enough for all nodes (max total pattern length)
    int head = 0, tail = 0;
    nodes[0].link = 0;
    // initialize children of root
    for (int c = 0; c < ALPH; ++c) {
        if (nodes[0].next[c] != -1) {
            nodes[nodes[0].next[c]].link = 0;
            q[tail++] = nodes[0].next[c];
        } else {
            nodes[0].next[c] = 0; // go to root
        }
    }
    while (head < tail) {
        int v = q[head++];
        // propagate output links
        int link = nodes[v].link;
        if (nodes[link].out != -1) {
            nodes[v].out_next = &nodes[link];
        }
        for (int c = 0; c < ALPH; ++c) {
            if (nodes[v].next[c] != -1) {
                nodes[nodes[v].next[c]].link = nodes[ nodes[v].link ].next[c];
                q[tail++] = nodes[v].next[c];
            } else {
                nodes[v].next[c] = nodes[ nodes[v].link ].next[c];
            }
        }
    }
}

void process_lyric(const char *s) {
    int v = 0;
    for (int i = 0; s[i]; ++i) {
        unsigned char c = s[i];
        v = nodes[v].next[c];
        // report matches at node v and via output links
        int cur = v;
        while (cur != -1) {
            if (nodes[cur].out != -1) {
                for (OutNode *o = &out_nodes[nodes[cur].out]; o != NULL; o = o->next) {
                    freq[o->idx]++;
                }
            }
            if (nodes[cur].out_next) cur = nodes[cur].out_next - nodes; // pointer arithmetic to get index
            else break;
        }
    }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int W; scanf("%d", &W);
        char **patterns = (char**)malloc(W * sizeof(char*));
        for (int i = 0; i < W; ++i) {
            patterns[i] = (char*)malloc(5005);
            scanf("%s", patterns[i]);
        }
        int N; scanf("%d", &N);
        char **lyrics = (char**)malloc(N * sizeof(char*));
        for (int i = 0; i < N; ++i) {
            lyrics[i] = (char*)malloc(50005);
            scanf("%s", lyrics[i]);
        }
        // allocate structures (worst case total nodes = sum lengths of patterns + 1)
        int max_nodes = 1;
        for (int i = 0; i < W; ++i) max_nodes += strlen(patterns[i]);
        nodes = (Node*)calloc(max_nodes, sizeof(Node));
        out_nodes = (OutNode*)calloc(W, sizeof(OutNode)); // at most one out per pattern
        node_cnt = 0; out_cnt = 0;
        new_node(); // root
        for (int i = 0; i < W; ++i) add_pattern(patterns[i], i);
        build_automaton();
        freq = (int*)calloc(W, sizeof(int));
        for (int i = 0; i < N; ++i) process_lyric(lyrics[i]);
        for (int i = 0; i < W; ++i) printf("%d\n", freq[i]);
        // free memory for this test case
        for (int i = 0; i < W; ++i) free(patterns[i]);
        free(patterns);
        for (int i = 0; i < N; ++i) free(lyrics[i]);
        free(lyrics);
        free(nodes);
        free(out_nodes);
        free(freq);
    }
    return 0;
}
